## 转换过程的映射关系

```python
# 原始数据
sample = {
    "questions": [Q1, Q2, Q3],     # 3个问题
    "answers": [
        [A1_obj1, A1_obj2],        # Q1的答案：2个物体
        [A2_obj1],                 # Q2的答案：1个物体
        [A3_obj1, A3_obj2, A3_obj3] # Q3的答案：3个物体
    ]
}

# 转换后的数据
output = [
    {  # Entry 1
        "text": Q1,
        "mask": {
            "0": [A1_obj1 + A1_obj2],  # union
            "1": [A1_obj1],             # 分类1
            "2": [A1_obj2]              # 分类2
        }
    },
    {  # Entry 2
        "text": Q2,
        "mask": {
            "0": [A2_obj1],
            "1": [A2_obj1]
        }
    },
    {  # Entry 3
        "text": Q3,
        "mask": {
            "0": [A3_obj1 + A3_obj2 + A3_obj3],
            "1": [A3_obj1],
            "2": [A3_obj2],
            "3": [A3_obj3]
        }
    }
]
```

## 代码中的处理逻辑

```python
def process_single_sample(sample: Dict) -> List[Dict]:
    questions = sample.get("questions", [])      # 获取多个问题
    answers_list = sample.get("answers", [])     # 获取多个答案组

    processed_entries = []

    # 遍历每个 (问题, 答案组) 对
    for question, answer_group in zip(questions, answers_list):
        #     ^^^^^^^^   ^^^^^^^^^^^^
        #     一个问题    一组答案（可能包含多个物体标注）

        # 在这个答案组内，按类别分组
        category_masks = defaultdict(list)
        all_masks = []

        for anno in answer_group:  # 遍历答案组内的每个标注
            seg = anno.get("segmentation")
            if seg:
                all_masks.append(seg)
                cat_name = anno.get("category_name")
                category_masks[cat_name].append(seg)

        # 为这个问题创建一个entry
        entry = {
            "text": question,           # 单个问题
            "mask": {...},              # 这个问题相关的所有物体
            "class_names": list(category_masks.keys())
        }
        processed_entries.append(entry)

    return processed_entries  # 返回多个entry（每个问题一个）
```

