  {  // Entry 2: Q2 + Q2的答案
    "text": "If someone were to plug in...",
    "class_names": ["laptop computer:cable"]
  },
  {  // Entry 3: Q3 + Q3的答案
    "text": "Where is the rest area...",
    "class_names": ["napkin"]
